/* ================================================================
 * Transight Design System — 시맨틱 토큰 (다크모드 대응)
 *
 * 컴포넌트/호출부는 raw 색(bg-cool-grey-*, bg-white 등) 금지, 항상 시맨틱.
 *   <div class="bg-card text-fg-default border-border-default">
 *
 * 매핑 원칙:
 *   foreground 4단 — strong / default / muted / disabled
 *   surface    5단 — page / card / subtle / muted / inverse
 *   border     3단 — default / subtle / strong
 *   상태       — ring-focus / overlay / hover-bg / active-bg
 *   shadow     3단 — card / dialog / popover
 *   gradient   4종 — cta / deep / fade-dark / glow
 *
 * shadcn 호환을 위해 기존 시맨틱(background/foreground/card/border/primary/...)도 유지.
 * 새 시맨틱은 fg-* / bg-* / border-* / shadow-* 접두로 별도 운영.
 * ================================================================ */

@custom-variant dark (&:is(.dark *));

/* ──────────────────────────────────────────────────────────────────
 * 라이트 모드
 * ────────────────────────────────────────────────────────────────── */
:root {
  --radius: 0.625rem;

  /* ── Foreground (텍스트 위계 4단) ───────────────── */
  --fg-strong: var(--color-cool-grey-11);       /* 헤더/강조 */
  --fg-default: var(--color-cool-grey-09);      /* 본문 (가장 많이) */
  --fg-muted: var(--color-cool-grey-07);        /* 보조/캡션 */
  --fg-disabled: var(--color-cool-grey-05);     /* 비활성 */
  --fg-inverse: var(--color-cool-grey-white);   /* 어두운 표면 위 텍스트 */

  /* ── Surface (배경 위계 5단) ───────────────────── */
  --bg-page: var(--color-cool-grey-white);      /* 페이지 본 배경 */
  --bg-card: var(--color-cool-grey-white);      /* 카드/팝업/dialog 표면 */
  --bg-subtle: var(--color-cool-grey-01);       /* 더 옅은 면 (테이블 stripe 등) */
  --bg-muted: var(--color-cool-grey-02);        /* hover/소프트 강조 */
  --bg-inverse: var(--color-cool-grey-11);      /* 사이드바·툴팁 (항상 짙음) */

  /* ── Border 3단 ───────────────────────────────── */
  --border-default: var(--color-cool-grey-04);
  --border-subtle: var(--color-cool-grey-03);
  --border-strong: var(--color-cool-grey-06);

  /* ── 상태 / 인터랙션 ────────────────────────────── */
  --ring-focus: rgb(21 109 252 / 0.5);                              /* primary-blue-1/50 */
  --overlay-backdrop: rgb(0 0 0 / 0.4);
  --hover-bg: var(--color-cool-grey-01);
  --active-bg: var(--color-cool-grey-02);

  /* ── Scrollbar ────────────────────────────────── */
  --scrollbar-subtle-thumb: rgb(0 0 0 / 0.18);
  --scrollbar-subtle-thumb-hover: rgb(0 0 0 / 0.32);
  --scrollbar-on-dark-thumb: rgb(255 255 255 / 0.15);
  --scrollbar-on-dark-thumb-hover: rgb(255 255 255 / 0.3);

  /* ── Shadow ────────────────────────────────────── */
  --shadow-card: 0 1px 3px rgb(0 0 0 / 0.08), 0 1px 2px rgb(0 0 0 / 0.04);
  --shadow-popover: 0 4px 12px rgb(0 0 0 / 0.12), 0 2px 4px rgb(0 0 0 / 0.06);
  --shadow-dialog: 0 8px 24px rgb(0 0 0 / 0.15), 0 4px 8px rgb(0 0 0 / 0.08);

  /* ── Gradient ──────────────────────────────────── */
  --gradient-cta: linear-gradient(135deg, var(--color-primary-blue-1) 0%, var(--color-primary-blue-2) 100%);
  --gradient-deep: linear-gradient(90deg, var(--color-primary-blue-1) 0%, var(--color-primary-blue-deep) 100%);
  --gradient-fade-dark: linear-gradient(to top, rgb(255 255 255 / 0.92) 0%, rgb(255 255 255 / 0.32) 55%, transparent 100%);
  --gradient-glow: radial-gradient(circle, rgb(21 109 252 / 0.25) 0%, transparent 70%);

  /* ── shadcn 호환 시맨틱 (기존 컴포넌트 호환용 — 새 코드는 fg- / bg- 시맨틱 권장) ── */
  --background: var(--bg-page);
  --foreground: var(--fg-strong);
  --card: var(--bg-card);
  --card-foreground: var(--fg-strong);
  --popover: var(--bg-card);
  --popover-foreground: var(--fg-strong);
  --primary: var(--color-primary-blue-1);
  --primary-foreground: var(--fg-inverse);
  --secondary: var(--color-cool-grey-03);
  --secondary-foreground: var(--fg-default);
  --muted: var(--color-cool-grey-03);
  --muted-foreground: var(--fg-muted);
  --accent: var(--color-cool-grey-03);
  --accent-foreground: var(--fg-default);
  --destructive: var(--color-ui-red);
  --border: var(--border-default);
  --input: var(--border-default);
  --ring: var(--color-primary-blue-1);

  --chart-1: var(--color-ui-red);
  --chart-2: var(--color-ui-green);
  --chart-3: var(--color-ui-blue);
  --chart-4: var(--color-ui-yellow);
  --chart-5: var(--color-ui-orange);

  --sidebar: var(--bg-inverse);
  --sidebar-foreground: var(--fg-inverse);
  --sidebar-primary: var(--color-primary-blue-1);
  --sidebar-primary-foreground: var(--fg-inverse);
  --sidebar-accent: var(--color-primary-skyblue-2);
  --sidebar-accent-foreground: var(--fg-inverse);
  --sidebar-border: rgb(255 255 255 / 0.1);
  --sidebar-ring: var(--color-cool-grey-08);
}

/* ──────────────────────────────────────────────────────────────────
 * 다크 모드
 * ────────────────────────────────────────────────────────────────── */
.dark {
  /* ── Foreground ────────────────────────────────── */
  --fg-strong: var(--color-cool-grey-white);
  --fg-default: var(--color-cool-grey-04);
  --fg-muted: var(--color-cool-grey-06);
  --fg-disabled: var(--color-cool-grey-08);
  --fg-inverse: var(--color-cool-grey-11);

  /* ── Surface ───────────────────────────────────── */
  --bg-page: var(--color-cool-grey-14);
  --bg-card: var(--color-cool-grey-13);
  --bg-subtle: var(--color-cool-grey-12);
  --bg-muted: var(--color-cool-grey-11);
  --bg-inverse: var(--color-cool-grey-02);   /* 다크에서 inverse는 밝은 표면 */

  /* ── Border ────────────────────────────────────── */
  --border-default: rgb(255 255 255 / 0.1);
  --border-subtle: rgb(255 255 255 / 0.05);
  --border-strong: rgb(255 255 255 / 0.2);

  /* ── 상태 ──────────────────────────────────────── */
  --ring-focus: rgb(55 94 240 / 0.6);                               /* primary-blue-accent/60 */
  --overlay-backdrop: rgb(0 0 0 / 0.7);
  --hover-bg: rgb(255 255 255 / 0.05);
  --active-bg: rgb(255 255 255 / 0.1);

  /* ── Scrollbar ────────────────────────────────── */
  --scrollbar-subtle-thumb: rgb(255 255 255 / 0.15);
  --scrollbar-subtle-thumb-hover: rgb(255 255 255 / 0.3);
  --scrollbar-on-dark-thumb: rgb(255 255 255 / 0.15);
  --scrollbar-on-dark-thumb-hover: rgb(255 255 255 / 0.3);

  /* ── Shadow (다크에서 알파 ↑) ──────────────────── */
  --shadow-card: 0 4px 15px rgb(0 0 0 / 0.4);
  --shadow-popover: 0 8px 24px rgb(0 0 0 / 0.45);
  --shadow-dialog: 0 32px 64px rgb(0 0 0 / 0.5);

  /* ── Gradient ──────────────────────────────────── */
  --gradient-cta: linear-gradient(135deg, var(--color-primary-blue-1) 0%, var(--color-primary-blue-2) 100%);
  --gradient-deep: linear-gradient(90deg, var(--color-primary-blue-1) 0%, var(--color-primary-blue-deep) 100%);
  --gradient-fade-dark: linear-gradient(to top, rgb(8 8 8 / 0.92) 0%, rgb(8 8 8 / 0.32) 55%, rgb(8 8 8 / 0.08) 100%);
  --gradient-glow: radial-gradient(circle, rgb(55 94 240 / 0.4) 0%, transparent 70%);

  /* ── shadcn 호환 ───────────────────────────────── */
  --background: var(--bg-page);
  --foreground: var(--fg-strong);
  --card: var(--bg-card);
  --card-foreground: var(--fg-strong);
  --popover: var(--bg-card);
  --popover-foreground: var(--fg-strong);
  --primary: var(--color-primary-blue-1);
  --primary-foreground: var(--fg-inverse);
  --secondary: var(--bg-muted);
  --secondary-foreground: var(--fg-default);
  --muted: var(--bg-muted);
  --muted-foreground: var(--fg-muted);
  --accent: var(--bg-muted);
  --accent-foreground: var(--fg-default);
  --destructive: var(--color-ui-red);
  --border: var(--border-default);
  --input: var(--border-default);
  --ring: var(--color-primary-blue-1);

  --chart-1: var(--color-primary-blue-1);
  --chart-2: var(--color-ui-green);
  --chart-3: var(--color-ui-orange);
  --chart-4: var(--color-ui-purple);
  --chart-5: var(--color-ui-red);

  --sidebar: var(--color-cool-grey-13);
  --sidebar-foreground: var(--fg-strong);
  --sidebar-primary: var(--color-primary-blue-1);
  --sidebar-primary-foreground: var(--fg-inverse);
  --sidebar-accent: var(--color-primary-skyblue-2);
  --sidebar-accent-foreground: var(--fg-inverse);
  --sidebar-border: rgb(255 255 255 / 0.1);
  --sidebar-ring: var(--color-cool-grey-06);
}

/* ──────────────────────────────────────────────────────────────────
 * Tailwind v4 — 시맨틱 → 유틸리티 자동 생성
 * 새 토큰은 @theme inline의 --color-* / --shadow-* / --background-image-* 키로 매핑
 * ────────────────────────────────────────────────────────────────── */
@theme inline {
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);

  /* Foreground — text-fg-{strong/default/muted/disabled/inverse} */
  --color-fg-strong: var(--fg-strong);
  --color-fg-default: var(--fg-default);
  --color-fg-muted: var(--fg-muted);
  --color-fg-disabled: var(--fg-disabled);
  --color-fg-inverse: var(--fg-inverse);

  /* Surface — bg-bg-{page/card/subtle/muted/inverse} */
  --color-bg-page: var(--bg-page);
  --color-bg-card: var(--bg-card);
  --color-bg-subtle: var(--bg-subtle);
  --color-bg-muted: var(--bg-muted);
  --color-bg-inverse: var(--bg-inverse);

  /* Border — border-border-{default/subtle/strong} */
  --color-border-default: var(--border-default);
  --color-border-subtle: var(--border-subtle);
  --color-border-strong: var(--border-strong);

  /* 상태 */
  --color-ring-focus: var(--ring-focus);
  --color-overlay-backdrop: var(--overlay-backdrop);
  --color-hover-bg: var(--hover-bg);
  --color-active-bg: var(--active-bg);

  /* Shadow — shadow-{card/popover/dialog} */
  --shadow-card: var(--shadow-card);
  --shadow-popover: var(--shadow-popover);
  --shadow-dialog: var(--shadow-dialog);

  /* Gradient — bg-gradient-{cta/deep/fade-dark/glow} */
  --background-image-gradient-cta: var(--gradient-cta);
  --background-image-gradient-deep: var(--gradient-deep);
  --background-image-gradient-fade-dark: var(--gradient-fade-dark);
  --background-image-gradient-glow: var(--gradient-glow);

  /* shadcn 호환 시맨틱 */
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
}

/* ──────────────────────────────────────────────────────────────────
 * 베이스 레이어
 * ────────────────────────────────────────────────────────────────── */
@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground;
  }

  /* a11y baseline — 모션 최소화 선호 사용자 대응 */
  @media (prefers-reduced-motion: reduce) {
    *,
    *::before,
    *::after {
      animation-duration: 0.001ms !important;
      animation-iteration-count: 1 !important;
      transition-duration: 0.001ms !important;
      scroll-behavior: auto !important;
    }
  }
}

/* ──────────────────────────────────────────────────────────────────
 * Scrollbar utilities
 *  - scrollbar-none: 스크롤바 완전 숨김 (가로 캐러셀 등)
 *  - scrollbar-subtle: 얇고 은은한 기본 커스텀 스크롤바
 *  - scrollbar-on-dark: 어두운 표면 위 커스텀 스크롤바
 *  - hide-scrollbar / custom-scrollbar / scrollbar-hide / scrollbar-custom: legacy alias
 * ────────────────────────────────────────────────────────────────── */
@utility scrollbar-none {
  scrollbar-width: none;
  -ms-overflow-style: none;
  &::-webkit-scrollbar {
    display: none;
  }
}

@utility hide-scrollbar {
  scrollbar-width: none;
  -ms-overflow-style: none;
  &::-webkit-scrollbar {
    display: none;
  }
}

@utility scrollbar-hide {
  scrollbar-width: none;
  -ms-overflow-style: none;
  &::-webkit-scrollbar {
    display: none;
  }
}

@utility scrollbar-subtle {
  scrollbar-width: thin;
  scrollbar-color: var(--scrollbar-subtle-thumb) transparent;
  &::-webkit-scrollbar {
    width: 6px;
  }
  &::-webkit-scrollbar-track {
    background: transparent;
  }
  &::-webkit-scrollbar-thumb {
    background: var(--scrollbar-subtle-thumb);
    border-radius: 3px;
  }
  &::-webkit-scrollbar-thumb:hover {
    background: var(--scrollbar-subtle-thumb-hover);
  }
}

@utility custom-scrollbar {
  scrollbar-width: thin;
  scrollbar-color: var(--scrollbar-subtle-thumb) transparent;
  &::-webkit-scrollbar {
    width: 6px;
  }
  &::-webkit-scrollbar-track {
    background: transparent;
  }
  &::-webkit-scrollbar-thumb {
    background: var(--scrollbar-subtle-thumb);
    border-radius: 3px;
  }
  &::-webkit-scrollbar-thumb:hover {
    background: var(--scrollbar-subtle-thumb-hover);
  }
}

@utility scrollbar-custom {
  scrollbar-width: thin;
  scrollbar-color: var(--scrollbar-subtle-thumb) transparent;
  &::-webkit-scrollbar {
    width: 6px;
  }
  &::-webkit-scrollbar-track {
    background: transparent;
  }
  &::-webkit-scrollbar-thumb {
    background: var(--scrollbar-subtle-thumb);
    border-radius: 3px;
  }
  &::-webkit-scrollbar-thumb:hover {
    background: var(--scrollbar-subtle-thumb-hover);
  }
}

@utility scrollbar-on-dark {
  scrollbar-width: thin;
  scrollbar-color: var(--scrollbar-on-dark-thumb) transparent;
  &::-webkit-scrollbar {
    width: 6px;
  }
  &::-webkit-scrollbar-track {
    background: transparent;
  }
  &::-webkit-scrollbar-thumb {
    background: var(--scrollbar-on-dark-thumb);
    border-radius: 3px;
  }
  &::-webkit-scrollbar-thumb:hover {
    background: var(--scrollbar-on-dark-thumb-hover);
  }
}
